"use client"

import React, { useEffect, useRef } from "react";
import { useRouter } from "next/navigation";
import { saveToken, isAuthenticated } from "../../utils/auth";
import styles from "../page.module.css";

const LoginPage = () => {
  const router = useRouter();
  const telegramRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Перевірити, чи вже авторизований
    if (isAuthenticated()) {
      router.push('/');
      return;
    }

    // Додати скрипт Telegram Login Widget
    const script = document.createElement('script');
    script.src = 'https://telegram.org/js/telegram-widget.js?22';
    script.setAttribute('data-telegram-login', 'ТУТ_BOT_USERNAME'); // TODO: Замінити на реальний bot username
    script.setAttribute('data-size', 'large');
    script.setAttribute('data-onauth', 'onTelegramAuth(user)');
    script.setAttribute('data-request-access', 'write');
    script.async = true;

    if (telegramRef.current) {
      telegramRef.current.appendChild(script);
    }

    // Глобальна функція для обробки авторизації
    (window as any).onTelegramAuth = async (user: any) => {
      console.log('Отримані дані від Telegram:', user);
      
      try {
        // Відправити дані на бекенд для отримання токену
        const response = await fetch('https://creator-store-server.onrender.com/api/auth/telegram', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            id: user.id,
            first_name: user.first_name,
            last_name: user.last_name,
            username: user.username,
            auth_date: user.auth_date,
            hash: user.hash,
          }),
        });

        if (response.ok) {
          const data = await response.json();
          console.log('Отримані дані від API:', data);
          
          // Зберегти токен
          if (data.token) {
            saveToken(data.token);
            alert('Авторизація успішна!');
            router.push('/');
          } else {
            alert('Помилка: токен не отримано');
          }
        } else {
          const errorData = await response.json();
          alert(`Помилка авторизації: ${errorData.message || response.status}`);
        }
      } catch (error) {
        console.error('Помилка при авторизації:', error);
        alert('Помилка при з\'єднанні з сервером');
      }
    };

    return () => {
      // Очистити глобальну функцію
      delete (window as any).onTelegramAuth;
    };
  }, [router]);

  return (
    <div className={styles.container}>
      <header className={styles.header}>
        <img src="/images/logo.jpg" alt="Logo" width={180} height={90} className={styles.logo} />
        <h1 className={styles.title}>АВТОРИЗАЦІЯ <span className={styles.by}>by</span> CREATOR IT ACADEMY</h1>
      </header>
      
      <div style={{ 
        display: 'flex', 
        flexDirection: 'column', 
        alignItems: 'center', 
        justifyContent: 'center', 
        minHeight: '400px',
        gap: '20px'
      }}>
        <h2 style={{ color: '#fff', fontSize: '24px' }}>Увійдіть через Telegram</h2>
        <p style={{ color: '#ccc', fontSize: '16px', textAlign: 'center', maxWidth: '400px' }}>
          Для створення замовлень необхідно авторизуватись через Telegram
        </p>
        <div ref={telegramRef}></div>
      </div>
    </div>
  );
};

export default LoginPage;
